mapper.update:
update student set name = #{name},no = #{no},gender=#{gender},phone = #{phone},degree = #{degree},
                   id_card = #{idCard},is_college = #{isCollege},address = #{address},
                   graduation_date= #{graduationDate},violation_count=#{violationCount}
                   ,violation_score = #{violationScore},clazz_id=#{clazzId} where id = #{id};

mapper.select:
SELECT student.id, student.name, no, gender, phone, id_card, is_college, address, degree, graduation_date, clazz_id, violation_count, violation_score, student.create_time,student. update_time,clazz.name clazzName from student
    left join clazz on
    clazz_id = clazz.id


        and student.name like concat('%',#{name},'%')


        and degree = #{degree}


        and clazz_id = #{clazzId}
